import React, { useState, useEffect, useRef, useMemo, useCallback } from 'react';
import { Routes, Route, useNavigate, useParams, NavLink, useLocation } from 'react-router-dom';
import { createResourceService } from '../../services/api.service';
import { useNotifier } from '../../context/NotificationContext';
import { Serializer } from '../../utils/serializer';
import { setPageTitle } from '../../hooks/usePageTitle';
import Icon from '../../components/common/Icon';
import { icons } from '../../config/icons';
import PageLoader from '../../components/common/PageLoader';
import moment from 'moment';
import DataTable from '../../components/common/DataTable';
import RichTextEditor from '../../components/common/RichTextEditor';
import useForm from '../../hooks/useForm';
import { FormInput } from '../../components/common/FormFields';

const tabbedService = createResourceService('clients');
// Component for the main form content
const DetailsTabContent = ({ values, errors, handleChange, isEditMode, photoPreview, handlePhotoChange, loading }) => {
    return (<div>
        {loading ?
            (<div className='pagelet-in'>
                <PageLoader type='profileSquare' className='profile-loading' />
            </div>) :
            (<>
                <div className='pagelet-in'>
                    <div className='form-case'>
                        <div className='form-row form-profile'>
                            <div className='form-profile-photo'>
                                <img src={photoPreview || '/defaults/avatar.png'} alt='Profile Preview' loading='lazy' onError={(e) => { e.target.onerror = null; e.target.src = '/defaults/avatar.png'; }} />
                                <label htmlFor='photo-upload'>Select Photo</label>
                                <input id='photo-upload' type='file' accept='image/*' onChange={handlePhotoChange} style={{ display: 'none' }} />
                            </div>
                            <div className='form-profile-info'>
                                <div className='form-row'>
                                    <FormInput label="First Name" name="fn" placeholder="First Name" value={values.fn} error={errors.fn} onChange={handleChange} required className="w5-fx" />
                                    <FormInput label="Middle Name" name="mn" placeholder="Middle Name" value={values.mn} onChange={handleChange} className="w5-fx" />
                                </div>
                                <FormInput label="Last Name" name="sn" placeholder="Last Name" value={values.sn} error={errors.sn} onChange={handleChange} required />
                            </div>
                        </div>
                    </div>
                </div>
                <div className='pagelet-foot'>
                    <button type='submit' form='tabbed_form' className='button btn-primary'> <Icon icon={isEditMode ? icons.edit : icons.save} /> {isEditMode ? 'Update' : 'Save'} </button>
                </div>
            </>)
        }
    </div>);
};
const SettingsTabContent = ({ values, setValues }) => <div className='pagelet-in'><div className='form-case'>
    <h3 className='h3'>Settings : {values?.fn} {values?.sn}</h3>
    <div className='input-case'> <p>Address</p> <RichTextEditor value={values?.address || ''} onChange={(val) => setValues(prev => ({ ...prev, address: val }))} placeholder="Enter the address here..." /> </div>
</div></div>;
const HistoryTabContent = ({ values }) => <div className='pagelet-in'><div className='wrap'><h3 className='h3'>History</h3><p>History content for {values?.fn} {values?.sn}.</p></div></div>;

const ChildPageTabs = ({ onSuccess }) => {
    const location = useLocation();
    const navigate = useNavigate();
    const { notify } = useNotifier();

    const { id: encodedId, tab } = useParams();
    const tableState = useMemo(() => location.state?.tableState || {}, [location.state]);

    const decodedId = useMemo(() => {
        if (encodedId === 'new') return 'new';
        try { return Serializer.decode(encodedId); }
        catch (e) { console.error("Failed to decode ID:", e); return null; }
    }, [encodedId]);
    const isEditMode = encodedId !== 'new';

    const [item, setItem] = useState(null);
    const [loading, setLoading] = useState(isEditMode);
    const [error, setError] = useState(null);

    const [allClientIds, setAllClientIds] = useState([]);
    const [currentIndex, setCurrentIndex] = useState(-1);

    const [photoPreview, setPhotoPreview] = useState(null);
    const [photoFile, setPhotoFile] = useState(null);
    const lastIdRef = useRef(null);

    useEffect(() => {
        if (!isEditMode) { setPageTitle('New Employee'); }
        else {
            if (loading) { setPageTitle('Loading Employee...'); }
            else if (item) { setPageTitle(`${item.fn} ${item.sn}`); }
            else { setPageTitle('Edit Employee'); }
        }
    }, [isEditMode, item, loading]);

    useEffect(() => {
        const fetchAllClientIds = async () => {
            try {
                const pars = { ...tableState };
                if (pars.filters) {
                    Object.assign(pars, pars.filters);
                    delete pars.filters;
                }

                const queryParams = {
                    ...pars,
                    page: 1,
                    limit: 100000,
                    searchableColumns: ['fn', 'sn', 'email', 'phone'].join(',')
                };

                const response = await tabbedService.getAll(queryParams);
                const ids = response.data.data.map(client => client.id);
                setAllClientIds(ids);
            } catch (err) {
                console.error('Failed to fetch client IDs:', err);
            }
        };

        fetchAllClientIds();
    }, [tableState]);

    useEffect(() => {
        if (decodedId && decodedId !== 'new' && allClientIds.length > 0) {
            const index = allClientIds.findIndex(id => id == decodedId);
            setCurrentIndex(index);
        }
    }, [decodedId, allClientIds]);

    const schema = useMemo(() => ({
        fn: { required: true, label: 'First Name' },
        sn: { required: true, label: 'Last Name' },
        email: { required: true, type: 'email', label: 'Email Address' }
    }), []);

    const initialValues = useMemo(() => ({
        fn: '',
        mn: '',
        sn: '',
        phone: '',
        email: '',
        address: '',
    }), []);

    const { values, errors, handleChange, handleSubmit, setValues, resetForm } = useForm(initialValues, schema);

    useEffect(() => {
        let isMounted = true;
        if (isEditMode && !decodedId) {
            notify({ message: 'Invalid Record ID.', style: 'error' });
            navigate('/admin/table-tab', { replace: true });
            return;
        }

        if (isEditMode) {
            if (lastIdRef.current !== decodedId) {
                setValues({ fn: '', mn: '', sn: '', phone: '', email: '', address: '' });
                setPhotoFile(null);
                setLoading(true);
                lastIdRef.current = decodedId;
            }

            tabbedService.getAll({ id: decodedId, _t: Date.now() }).then(response => {
                if (isMounted) {
                    const employeeData = response.data.data[0];
                    if (employeeData) {
                        setItem(employeeData);
                        setValues({
                            fn: employeeData.fn || '',
                            mn: employeeData.mn || '',
                            sn: employeeData.sn || '',
                            phone: employeeData.phone || '',
                            email: employeeData.email || '',
                            address: employeeData.address || '',
                        });
                        if (employeeData.photoUrl) {
                            const photoUrlWithCacheBust = `${employeeData.photoUrl}?t=${Date.now()}`;
                            tabbedService.getPhoto(photoUrlWithCacheBust).then(photoResp => {
                                if (isMounted) setPhotoPreview(URL.createObjectURL(photoResp.data));
                            }).catch(() => {
                                if (isMounted) setPhotoPreview('/defaults/avatar.png');
                            });
                        }
                        else { setPhotoPreview('/defaults/avatar.png'); }
                    }
                    else { notify({ message: 'Record not found.', style: 'error' }); navigate('/admin/table-tab'); }
                }
            }).catch(() => {
                if (isMounted) { setError('Failed to fetch data.'); notify({ message: 'Failed to fetch data.', style: 'error' }); }
            }).finally(() => {
                if (isMounted) setLoading(false);
            });
        }
        else { 
            setItem({}); 
            resetForm();
            setLoading(false); 
            setPhotoPreview('/defaults/avatar.png'); 
        }

        return () => { isMounted = false; };
    }, [decodedId, isEditMode, navigate, notify, resetForm, setValues]);

    useEffect(() => {
        if (isEditMode && location.pathname.split('/').length === 4) {
            navigate(`/admin/table-tab/details/${encodedId}`, { replace: true });
        }
    }, [location.pathname, encodedId, isEditMode, navigate]);


    const handleSave = async (formValues, itemId) => {
        try {
            const formData = new FormData();
            Object.keys(formValues).forEach(key => {
                if (formValues[key]) formData.append(key, formValues[key]);
            });
            if (photoFile) formData.append('photo', photoFile);

            let response;
            if (itemId) {
                response = await tabbedService.update(itemId, formData);
                notify({ message: 'Updated successfully.', style: 'success' });
            } else {
                response = await tabbedService.create(formData);
                notify({ message: 'Created successfully.', style: 'success' });
            }

            const updatedRecord = response.data.data || response.data;
            const newPhotoTs = photoFile ? Date.now() : null;

            if (onSuccess) {
                onSuccess(itemId, updatedRecord, newPhotoTs);
            }

            navigate('/admin/table-tab');
        } catch (err) { notify({ message: `Failed to save. ${err.message}`, style: 'error' }); }
    };

    const onFormSubmit = (formValues) => {
        handleSave(formValues, isEditMode ? decodedId : null);
    };

    const handlePhotoChange = (e) => {
        const file = e.target.files[0];
        if (file) {
            setPhotoFile(file);
            setPhotoPreview(URL.createObjectURL(file));
        }
    };

    const handleBack = () => navigate('/admin/table-tab');

    const handlePrevious = () => {
        if (currentIndex > 0) {
            const prevId = allClientIds[currentIndex - 1];
            const currentTab = tab || 'details';
            navigate(`/admin/table-tab/${currentTab}/${Serializer.encode(prevId)}`, { state: { tableState } });
        }
    };

    const handleNext = () => {
        if (currentIndex < allClientIds.length - 1) {
            const nextId = allClientIds[currentIndex + 1];
            const currentTab = tab || 'details';
            navigate(`/admin/table-tab/${currentTab}/${Serializer.encode(nextId)}`, { state: { tableState } });
        }
    };

    if (error) return <div className='admin-pager'>{error}</div>;

    const tabs = [
        { path: 'details', label: 'Details' },
        { path: 'settings', label: 'Settings' },
        { path: 'history', label: 'History' },
    ];
    const renderTabContent = () => {
        const props = { values, errors, handleChange, setValues, isEditMode, photoPreview, handlePhotoChange, loading };
        switch (tab) {
            case 'settings': return <SettingsTabContent {...props} />;
            case 'history': return <HistoryTabContent {...props} />;
            case 'details':
            default: return <DetailsTabContent {...props} />;
        }
    };

    return (
        <div className='admin-pager'>
            <header className='admin-pager-head'>
                <div className='admin-pager-title'>
                    <button className='admin-pager-back' onClick={handleBack}><Icon icon={icons.chevronLeft} /></button>
                    <span>
                        <h2>{isEditMode ? 'Edit Record' : 'Add Record'}</h2>
                        <p>{isEditMode ? item ? `${item.fn} ${item.sn}` : 'Loading...' : 'Create New Record'}</p>
                    </span>
                </div>
                <div className='admin-pager-navs'>
                    {isEditMode && allClientIds.length > 1 && (
                        <>
                            <button className='button btn-outlined icon' title='Previous' onClick={handlePrevious} disabled={currentIndex <= 0} > <Icon icon={icons.chevronLeft} /> </button>
                            <button className='button btn-outlined icon' title='Next' onClick={handleNext} disabled={currentIndex >= allClientIds.length - 1} > <Icon icon={icons.chevronRight} /> </button>
                        </>
                    )}
                </div>
            </header>
            <div className='flex-case'>
                <div className='w6'>
                    <form className='pagelet' noValidate id='tabbed_form' onSubmit={handleSubmit(onFormSubmit)} autoComplete='off' >
                        <div className='tab-case bordered'>
                            <ul> {tabs.map((tabItem) => (<li key={tabItem.path}><NavLink className={({ isActive }) => `nav-link ${isActive ? 'active' : ''}`} state={{ tableState }} to={`/admin/table-tab/${tabItem.path}/${encodedId}`} > {tabItem.label} </NavLink></li>))} </ul>
                        </div>
                        {renderTabContent()}
                    </form>
                </div>
            </div>
        </div>
    );
};

const EmployeeListTabs = ({ tableRef, initialLoadTime, photoOverrides }) => {
    const navigate = useNavigate();
    const [tableState, setTableState] = useState({});

    const tableColumns = useMemo(() => [{
        key: 'fn', label: 'Full Name', type: 0, class: 'mob-flex', sortable: true,
        render: (item, photoUrl) => {
            let displayUrl = photoUrl || '/default/avatar.png';
            if (displayUrl.includes('?')) displayUrl = displayUrl.split('?')[0];

            const timestampToUse = photoOverrides[item.id] || initialLoadTime;
            displayUrl = `${displayUrl}?t=${timestampToUse}`;

            return (
                <div className='td-user'>
                    <div className='td-user-photo'>
                        <img
                            key={displayUrl}
                            src={displayUrl}
                            alt={`${item.fn} ${item.sn}`}
                            loading='lazy'
                            onError={(e) => { e.target.onerror = null; e.target.src = '/default/avatar.png'; }}
                        />
                    </div>
                    <div className='tr-name'>
                        <b className='link' onClick={() => navigate(`/admin/table-tab/details/${Serializer.encode(item.id)}`, { state: { tableState } })}>
                            {`${item.fn} ${item.mn ? item.mn : ''} ${item.sn}`}
                        </b>
                        <p>{item.email}</p>
                    </div>
                </div>
            );
        }
    },
    { key: 'phone', label: 'Phone', type: 1, class: 'mob-full', sortable: true },
    { key: 'bday', label: 'Birthday', type: 1, class: 'mob-full', sortable: true, render: (item) => item.bday ? moment(item.bday).format('MMM DD, YYYY') : '' },
    { key: 'address', label: 'Address', type: 1, class: 'mob-full', sortable: true },
    ], [navigate, tableState, photoOverrides, initialLoadTime]);

    const headerActions = useMemo(() => [{ text: 'Add New', icon: icons.add, onClick: () => navigate('/admin/table-tab/details/new'), className: '' }], [navigate]);

    return (
        <DataTable
            key='tabbed-datatable'
            ref={tableRef}
            resourceName='Client'
            apiService={tabbedService}
            columns={tableColumns}
            config={{ add: false, edit: false, searchables: ['fn', 'sn', 'email', 'phone'], headerActions: headerActions, onStateChange: setTableState }}
        />
    );
};

const CombinedView = () => {
    const { id } = useParams();
    const showChildPage = id !== undefined;
    const tableRef = useRef(null);

    const initialLoadTime = useMemo(() => Date.now(), []);
    const [photoOverrides, setPhotoOverrides] = useState({});

    const handleListUpdate = useCallback((itemId, updatedData, newPhotoTs) => {
        if (itemId && newPhotoTs) { setPhotoOverrides(prev => ({ ...prev, [itemId]: newPhotoTs })); }
        if (tableRef.current) {
            tableRef.current.refreshData();
        }
    }, []);

    return (
        <div>
            <div style={{ display: showChildPage ? 'none' : 'block' }}>
                <EmployeeListTabs
                    tableRef={tableRef}
                    initialLoadTime={initialLoadTime}
                    photoOverrides={photoOverrides}
                />
            </div>
            {showChildPage && <ChildPageTabs onSuccess={handleListUpdate} />}
        </div>
    );
};

const Tabbed = () => {
    return (
        <Routes>
            <Route index element={<CombinedView />} />
            <Route path=':tab/:id' element={<CombinedView />} />
        </Routes>);
};

export default Tabbed;